sql:
SELECT body_number, recovery_date, burial_location, body_found_location, body_condition
FROM passenger_body_details
WHERE passenger_id = 1;

SELECT AVG(age) AS average_age
FROM passengers
WHERE pclass = 1 AND embarked = 'Q';

SELECT name
FROM passengers
WHERE has_cabin_number = 1 AND survived = 1;

SELECT passengers.name, home_destinations.destination_name
FROM passengers
JOIN home_destinations ON passengers.home_destination = home_destinations.destination_name;

SELECT name, cabin_number 
FROM passengers 
WHERE has_cabin_number = 1;

external_knowledge:
- 'journeyed but did not return to port' refers to passengers who did not survive (body_number IS NULL);
- 'voyages' chambers' are the cabin numbers where they stayed during the voyage;
- 'ticket prices' are the fares they paid for the tickets;
- 'cost of their restful accommodations' is the cabin price;
- 'depth of their sea chests' metaphorically represents the total fare sum (total_spent) which indicates the total amount of money each spent, calculated as the sum of the fares for each ticket;
- 'the five deepest of these oceanic coffers' means the top 5 passengers by total_spent.

sql:
SELECT SUM(pe.port_population) AS total_port_population
FROM passengers p
INNER JOIN ports_of_embarkation pe ON p.embarked = pe.port_code;

SELECT passenger_id, has_cabin_number, boat_number 
FROM passengers 
WHERE pclass = 1 AND has_cabin_number = 1 AND boat_number IS NULL;

SELECT passenger_id, name, cabin_number
FROM passengers
WHERE survived = 1 AND has_cabin_number = 1;

SELECT AVG(age) AS average_age
FROM passengers
WHERE embarked = 'S' AND pclass = 3 AND survived = 1;
